package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Random;

import org.eclipse.rdf4j.query.algebra.TupleExpr;

/** Seeded random trees, each paired with a 1-2 step mutator chain applied to it. */
final class RandomTreePairSource {
	private final RandomTreeGenerator generator = new RandomTreeGenerator();
	private final List<TupleExprMutator> mutators = MutatorLibrary.all();

	List<TreePair> pairs(long seed, int count) {
		List<TreePair> result = new ArrayList<>(count);
		for (int i = 0; i < count; i++) {
			long pairSeed = seed + i;
			Random rnd = new Random(pairSeed * 31 + 7);
			TupleExpr original = generator.generate(pairSeed);
			TupleExpr candidate = original;
			List<String> chain = new ArrayList<>();
			TreePair.Expectation expectation = TreePair.Expectation.PRESERVING;
			int chainLength = 1 + rnd.nextInt(2);
			for (int step = 0; step < chainLength; step++) {
				TupleExprMutator mutator = mutators.get(rnd.nextInt(mutators.size()));
				Optional<TupleExpr> mutated = mutator.apply(candidate, rnd);
				if (mutated.isPresent()) {
					candidate = mutated.get();
					chain.add(mutator.name());
					expectation = combine(expectation, mutator.expectation());
				}
			}
			if (chain.isEmpty()) {
				candidate = original.clone();
				chain.add("clone-identity");
			}
			result.add(new TreePair("random-" + i, "random", pairSeed, chain, original, candidate, expectation));
		}
		return result;
	}

	private static TreePair.Expectation combine(TreePair.Expectation left, TreePair.Expectation right) {
		if (left == TreePair.Expectation.PRESERVING && right == TreePair.Expectation.PRESERVING) {
			return TreePair.Expectation.PRESERVING;
		}
		return TreePair.Expectation.UNSPECIFIED;
	}
}
